proof fn phi_1_fold_left_append_len_empty_prefix<A, B>(s: Seq<A>, f: spec_fn(A) -> Seq<B>)
    ensures
        s.fold_left(Seq::<B>::empty(), |sb: Seq<B>, a: A| sb + f(a)).len() as int
        ==
        s.fold_left(0int, |i: int, a: A| i + f(a).len() as int),
{
    lemma_seq_fold_left_append_len_int::<A, B>(s, Seq::<B>::empty(), f);
}

proof fn phi_2_fold_left_empty_seq_identity<A, B>(prefix: Seq<B>, f: spec_fn(A) -> Seq<B>)
    ensures
        Seq::<A>::empty().fold_left(prefix, |sb: Seq<B>, a: A| sb + f(a)).len() as int
        ==
        prefix.len() as int,
{
    lemma_seq_fold_left_append_len_int::<A, B>(Seq::<A>::empty(), prefix, f);
}

proof fn phi_3_fold_left_int_accumulator_no_lower_bound<A, B>(s: Seq<A>, prefix: Seq<B>, f: spec_fn(A) -> Seq<B>)
    ensures
        s.fold_left(prefix.len() as int, |i: int, a: A| i + f(a).len() as int) >= prefix.len() as int,
{
    lemma_seq_fold_left_append_len_int::<A, B>(s, prefix, f);
}

proof fn phi_4_fold_left_singleton_len<A, B>(a: A, prefix: Seq<B>, f: spec_fn(A) -> Seq<B>)
    ensures
        seq![a].fold_left(prefix, |sb: Seq<B>, x: A| sb + f(x)).len() as int
        ==
        prefix.len() as int + f(a).len() as int,
{
    lemma_seq_fold_left_append_len_int::<A, B>(seq![a], prefix, f);
}

proof fn phi_5_fold_left_append_associativity<A, B>(s1: Seq<A>, s2: Seq<A>, prefix: Seq<B>, f: spec_fn(A) -> Seq<B>)
    ensures
        s1.add(s2).fold_left(prefix, |sb: Seq<B>, a: A| sb + f(a)).len() as int
        ==
        s2.fold_left(
            s1.fold_left(prefix.len() as int, |i: int, a: A| i + f(a).len() as int),
            |i: int, a: A| i + f(a).len() as int
        ),
{
    lemma_seq_fold_left_append_len_int::<A, B>(s1.add(s2), prefix, f);
    lemma_seq_fold_left_append_len_int::<A, B>(s1, prefix, f);
}
